const body = items[0]?.json || {};

function addDays(dateISO, days) {
  const d = new Date(dateISO);
  d.setDate(d.getDate() + days);
  return d.toISOString();
}
function atTime(dateISO, hh = 7, mm = 30, tzOffsetMin = null) {
  const d = new Date(dateISO);
  d.setUTCHours(hh, mm, 0, 0);
  return d.toISOString();
}
function rangeDays(startISO, days) {
  const out = [];
  for (let i = 0; i < days; i++) out.push(addDays(startISO, i));
  return out;
}

const tz = body.tz || 'America/Chicago';
const startDate = body.startDate || new Date().toISOString().slice(0,10);
const days = Math.max(1, Math.min(60, Number(body.days || 14)));

const animals = body.animals || [
  { species: 'chicken', purpose: 'layer', count: 10 },
  { species: 'goat', purpose: 'dairy', count: 2 },
  { species: 'bee', purpose: 'honey', hives: 1 }
];

const callbackUrl = body.callbackUrl || `${$env.SUKA_API_BASE || 'http://localhost:4000'}/automations/tasks`;
const userId = body.userId || null;

const tasks = [];

// Chickens (layers): daily feed AM/PM, collect eggs AM, coop clean weekly
const layers = animals.find(a => String(a.species).toLowerCase() === 'chicken' && String(a.purpose).toLowerCase() === 'layer');
if (layers && layers.count > 0) {
  rangeDays(startDate, days).forEach((dISO, idx) => {
    tasks.push({ title: 'Feed chickens (AM)', category: 'animal-care', labels: ['animal:chicken','feed'], due: atTime(dISO, 7, 30), meta: { species: 'chicken', count: layers.count, slot: 'am' }, priority: 2, callbackUrl, userId });
    tasks.push({ title: 'Collect eggs', category: 'animal-care', labels: ['animal:chicken','eggs'], due: atTime(dISO, 8, 0), meta: { species: 'chicken', count: layers.count }, priority: 2, callbackUrl, userId });
    tasks.push({ title: 'Feed chickens (PM)', category: 'animal-care', labels: ['animal:chicken','feed'], due: atTime(dISO, 17, 30), meta: { species: 'chicken', count: layers.count, slot: 'pm' }, priority: 2, callbackUrl, userId });
    if (idx % 7 === 0) {
      tasks.push({ title: 'Clean coop & refresh bedding', category: 'sanitation', labels: ['animal:chicken','cleaning'], due: atTime(dISO, 10, 0), priority: 3, callbackUrl, userId });
    }
  });
}

// Goats (dairy): milk AM/PM, hoof check biweekly
const goats = animals.find(a => String(a.species).toLowerCase() === 'goat' && String(a.purpose).toLowerCase() === 'dairy');
if (goats && goats.count > 0) {
  rangeDays(startDate, days).forEach((dISO, idx) => {
    tasks.push({ title: 'Milk goats (AM)', category: 'animal-care', labels: ['animal:goat','milk'], due: atTime(dISO, 6, 30), meta: { species: 'goat', count: goats.count, slot: 'am' }, priority: 1, callbackUrl, userId });
    tasks.push({ title: 'Milk goats (PM)', category: 'animal-care', labels: ['animal:goat','milk'], due: atTime(dISO, 18, 30), meta: { species: 'goat', count: goats.count, slot: 'pm' }, priority: 1, callbackUrl, userId });
    if (idx % 14 === 0) {
      tasks.push({ title: 'Goat hoof check', category: 'health', labels: ['animal:goat','health'], due: atTime(dISO, 11, 0), priority: 3, callbackUrl, userId });
    }
  });
}

// Bees: inspections every 2 weeks; honey super check monthly
const bees = animals.find(a => /bee|bees|honey/i.test(a.species));
if (bees && (bees.hives || bees.count || 0) > 0) {
  rangeDays(startDate, days).forEach((dISO, idx) => {
    if (idx % 14 === 0) tasks.push({ title: 'Hive inspection', category: 'inspection', labels: ['animal:bee','hive'], due: atTime(dISO, 9, 30), meta: { hives: bees.hives || bees.count }, priority: 3, callbackUrl, userId });
    if (idx % 28 === 0) tasks.push({ title: 'Honey super check', category: 'production', labels: ['animal:bee','honey'], due: atTime(dISO, 13, 0), meta: { hives: bees.hives || bees.count }, priority: 3, callbackUrl, userId });
  });
}

// Optional: feed procurement reminder if given remaining days
if (typeof body.feedInventoryDaysRemaining === 'number') {
  const thresh = Number(body.procureThresholdDays || 5);
  if (body.feedInventoryDaysRemaining < thresh) {
    tasks.push({ title: 'Buy animal feed', category: 'procurement', labels: ['feed','inventory'], due: atTime(addDays(startDate, 1), 12, 0), priority: 1, meta: { reason: 'low_feed', daysRemaining: body.feedInventoryDaysRemaining }, callbackUrl, userId });
  }
}

// Output: one item per task for downstream nodes; also attach summary on the first item for convenience
const itemsOut = tasks.map(t => ({ json: t }));
if (itemsOut.length === 0) {
  return [{ json: { info: 'No animals provided; nothing to schedule.' } }];
}
return itemsOut;

const stats = items.reduce((acc, it) => {
  const c = (it.json && it.json.category) || 'other';
  acc.total++;
  acc.byCategory[c] = (acc.byCategory[c] || 0) + 1;
  return acc;
}, { total: 0, byCategory: {} });

return [{ json: { ok: true, message: `Planned ${stats.total} tasks`, stats } }];
